// DaemonAdminServiceServer is the server API for DaemonAdminService service.
// All implementations must embed UnimplementedDaemonAdminServiceServer
// for forward compatibility.
//
// DaemonAdminService provides the internal admin gRPC API for Gibson daemon.
//
// This service exposes privileged operations including tenant lifecycle management,
// billing, provisioning, impersonation, API key management, and daemon shutdown.
// It is NEVER exposed to end-customers — only to platform operators and internal
// services.
type DaemonAdminServiceServer interface {
	// Shutdown requests graceful shutdown of the daemon.
	// This is used by the CLI to stop the daemon remotely.
	// Only works for local daemons (not when GIBSON_DAEMON_ADDRESS is set to remote).
	Shutdown(context.Context, *ShutdownRequest) (*ShutdownResponse, error)
	// CreateTenant creates a new tenant record.
	CreateTenant(context.Context, *CreateTenantRequest) (*CreateTenantResponse, error)
	// GetTenant retrieves a single tenant by ID.
	GetTenant(context.Context, *GetTenantRequest) (*GetTenantResponse, error)
	// ListTenants returns all tenants visible to the caller.
	ListTenants(context.Context, *ListTenantsRequest) (*ListTenantsResponse, error)
	// UpdateTenant applies updates to an existing tenant.
	UpdateTenant(context.Context, *UpdateTenantRequest) (*UpdateTenantResponse, error)
	// DeleteTenant soft-deletes a tenant.
	DeleteTenant(context.Context, *DeleteTenantRequest) (*DeleteTenantResponse, error)
	// ProvisionTenant triggers full tenant provisioning (namespace, RBAC,
	// initial API key, etc.).
	ProvisionTenant(context.Context, *ProvisionTenantRequest) (*ProvisionTenantResponse, error)
	// GetProvisioningStatus queries the provisioning progress for a tenant.
	GetProvisioningStatus(context.Context, *GetProvisioningStatusRequest) (*GetProvisioningStatusResponse, error)
	// DeprovisionTenant tears down all tenant resources.
	DeprovisionTenant(context.Context, *DeprovisionTenantRequest) (*DeprovisionTenantResponse, error)
	// ImpersonateTenant requests a time-limited context token for the given tenant.
	// Requires the "platform-operator" role.
	ImpersonateTenant(context.Context, *ImpersonateTenantRequest) (*ImpersonateTenantResponse, error)
	// UpdateTenantBilling updates billing fields on a tenant record.
	UpdateTenantBilling(context.Context, *UpdateTenantBillingRequest) (*UpdateTenantBillingResponse, error)
	// GetTenantBilling queries billing information for a tenant.
	GetTenantBilling(context.Context, *GetTenantBillingRequest) (*GetTenantBillingResponse, error)
	// GetTenantByStripeCustomerId queries a tenant by its Stripe customer ID.
	GetTenantByStripeCustomerId(context.Context, *GetTenantByStripeCustomerIdRequest) (*GetTenantByStripeCustomerIdResponse, error)
	// GetTenantByEmail queries a tenant by the owner's email address.
	GetTenantByEmail(context.Context, *GetTenantByEmailRequest) (*GetTenantByEmailResponse, error)
	// GetTenantLangfuseCredentials retrieves the Langfuse project credentials for a tenant.
	// Returns NOT_FOUND if no credentials have been configured for the tenant.
	GetTenantLangfuseCredentials(context.Context, *GetTenantLangfuseCredentialsRequest) (*GetTenantLangfuseCredentialsResponse, error)
	// SetTenantLangfuseCredentials stores or updates Langfuse project credentials for a tenant.
	SetTenantLangfuseCredentials(context.Context, *SetTenantLangfuseCredentialsRequest) (*SetTenantLangfuseCredentialsResponse, error)
	// DeleteTenantLangfuseCredentials removes the Langfuse project credentials for a tenant.
	DeleteTenantLangfuseCredentials(context.Context, *DeleteTenantLangfuseCredentialsRequest) (*DeleteTenantLangfuseCredentialsResponse, error)
	// GetOnboardingState queries the onboarding progress for a tenant.
	GetOnboardingState(context.Context, *GetOnboardingStateRequest) (*GetOnboardingStateResponse, error)
	// UpdateOnboardingState advances or modifies the onboarding state.
	UpdateOnboardingState(context.Context, *UpdateOnboardingStateRequest) (*UpdateOnboardingStateResponse, error)
	// CreateInvitation issues a new team invitation.
	CreateInvitation(context.Context, *CreateInvitationRequest) (*CreateInvitationResponse, error)
	// AcceptInvitation redeems an invitation token.
	AcceptInvitation(context.Context, *AcceptInvitationRequest) (*AcceptInvitationResponse, error)
	// ListInvitations returns the list of invitations for the caller's tenant.
	ListInvitations(context.Context, *ListInvitationsRequest) (*ListInvitationsResponse, error)
	// RevokeInvitation cancels a pending invitation.
	RevokeInvitation(context.Context, *RevokeInvitationRequest) (*RevokeInvitationResponse, error)
	// CreateAPIKey issues a new API key for a tenant.
	CreateAPIKey(context.Context, *CreateAPIKeyRequest) (*CreateAPIKeyResponse, error)
	// ListAPIKeys returns API key metadata (never raw key values).
	ListAPIKeys(context.Context, *ListAPIKeysRequest) (*ListAPIKeysResponse, error)
	// RevokeAPIKey permanently revokes an API key.
	RevokeAPIKey(context.Context, *RevokeAPIKeyRequest) (*RevokeAPIKeyResponse, error)
	// ListTenantMembers returns all members of a tenant.
	ListTenantMembers(context.Context, *ListTenantMembersRequest) (*ListTenantMembersResponse, error)
	// AddTenantMember adds a user to a tenant with the specified role.
	AddTenantMember(context.Context, *AddTenantMemberRequest) (*AddTenantMemberResponse, error)
	// RemoveTenantMember removes a user from a tenant.
	RemoveTenantMember(context.Context, *RemoveTenantMemberRequest) (*RemoveTenantMemberResponse, error)
	// UpdateMemberRole changes the role of an existing tenant member.
	UpdateMemberRole(context.Context, *UpdateMemberRoleRequest) (*UpdateMemberRoleResponse, error)
	// ListUserTenants returns all tenants a given user belongs to.
	ListUserTenants(context.Context, *ListUserTenantsRequest) (*ListUserTenantsResponse, error)
	// TransferOwnership transfers tenant ownership to another existing member.
	TransferOwnership(context.Context, *TransferOwnershipRequest) (*TransferOwnershipResponse, error)
	// SignupTenant orchestrates the full tenant signup flow: create Keycloak user,
	// create Keycloak Organization, add user as member, write the first FGA admin
	// tuple, and provision downstream tenant resources (Langfuse project, etc.).
	//
	// This RPC replaces the previous dashboard-side Keycloak admin orchestration
	// so that admin credentials never leave the daemon pod.
	//
	// Requires the caller to present a gibson-system-ops service account JWT with
	// the "provisioner" realm role (tenants:signup permission).
	//
	// Added by authz-02-keycloak-organizations spec.
	SignupTenant(context.Context, *SignupTenantRequest) (*SignupTenantResponse, error)
	// InviteMember creates a Keycloak user, adds them to the org, writes an FGA
	// tuple, and generates a signed invitation token. Requires FGA admin relation.
	InviteMember(context.Context, *InviteMemberRequest) (*InviteMemberResponse, error)
	// RemoveMember removes a user from the tenant: deletes the FGA tuple and
	// removes the Keycloak Organization membership. Requires FGA admin relation.
	RemoveMember(context.Context, *RemoveMemberRequest) (*RemoveMemberResponse, error)
	// ResendInvitation issues a fresh invitation token for an existing pending user.
	// Requires FGA admin relation.
	ResendInvitation(context.Context, *ResendInvitationRequest) (*ResendInvitationResponse, error)
	// ListUserComponentGrants returns the component grants for a user within a tenant.
	// Accessible by admins (for any user) or members (for themselves).
	ListUserComponentGrants(context.Context, *ListUserComponentGrantsRequest) (*ListUserComponentGrantsResponse, error)
	// GrantComponentAccess writes an FGA can_<action> tuple for the user on the component.
	// Requires FGA admin relation.
	GrantComponentAccess(context.Context, *GrantComponentAccessRequest) (*GrantComponentAccessResponse, error)
	// RevokeComponentAccess deletes the FGA can_<action> tuple for the user on the component.
	// Requires FGA admin relation.
	RevokeComponentAccess(context.Context, *RevokeComponentAccessRequest) (*RevokeComponentAccessResponse, error)
	// CreateTeam creates a new team within a tenant. Requires FGA admin relation.
	CreateTeam(context.Context, *CreateTeamRequest) (*CreateTeamResponse, error)
	// ListTeams returns all teams within a tenant.
	ListTeams(context.Context, *ListTeamsRequest) (*ListTeamsResponse, error)
	// DeleteTeam permanently removes a team and its FGA relationships.
	// Requires FGA admin relation.
	DeleteTeam(context.Context, *DeleteTeamRequest) (*DeleteTeamResponse, error)
	// AddUserToTeam adds a user to a team. Requires FGA admin relation.
	// The user must already be a member of the parent tenant.
	AddUserToTeam(context.Context, *AddUserToTeamRequest) (*AddUserToTeamResponse, error)
	// RemoveUserFromTeam removes a user from a team. Requires FGA admin relation.
	RemoveUserFromTeam(context.Context, *RemoveUserFromTeamRequest) (*RemoveUserFromTeamResponse, error)
	// SetTeamCrosstalk grants team A visibility into team B's data (directional).
	// Requires FGA admin relation.
	SetTeamCrosstalk(context.Context, *SetTeamCrosstalkRequest) (*SetTeamCrosstalkResponse, error)
	// ListAuditEvents returns audit events for a tenant, sourced from the daemon's
	// Redis audit stream. Requires FGA admin relation on the tenant.
	ListAuditEvents(context.Context, *ListAuditEventsRequest) (*ListAuditEventsResponse, error)
	// BatchGrantComponentAccess applies a list of grant/revoke operations in a
	// single RPC call, reducing round-trip count for bulk permission changes.
	// Requires FGA admin relation on the tenant.
	BatchGrantComponentAccess(context.Context, *BatchGrantComponentAccessRequest) (*BatchGrantComponentAccessResponse, error)
	// ResetPassword triggers a Keycloak password-reset email for the given address.
	// Always returns success regardless of whether the email exists, to prevent
	// email enumeration attacks.
	ResetPassword(context.Context, *ResetPasswordRequest) (*ResetPasswordResponse, error)
	// RevokeUserSessions revokes one or all active sessions for a user.
	// Delegates to Keycloak session management and emits a Redis pub/sub event.
	RevokeUserSessions(context.Context, *RevokeUserSessionsRequest) (*RevokeUserSessionsResponse, error)
	// SuspendMember disables or reactivates a tenant member via Keycloak.
	// When suspend=true the user is disabled and their FGA tuple is removed.
	// When suspend=false the user is re-enabled and the tuple is restored.
	SuspendMember(context.Context, *SuspendMemberRequest) (*SuspendMemberResponse, error)
	// GetUserProfile retrieves a user's profile information from Keycloak.
	// Accessible by the user themselves or by a tenant admin.
	GetUserProfile(context.Context, *GetUserProfileRequest) (*GetUserProfileResponse, error)
	// UpdateUserProfile updates mutable profile fields (display_name, avatar_url)
	// for a user in Keycloak. Email and role changes are not permitted here.
	UpdateUserProfile(context.Context, *UpdateUserProfileRequest) (*UpdateUserProfileResponse, error)
	// ExportFindings exports findings to the requested format (json, csv, sarif).
	// The serialized content is returned as bytes in the response.
	ExportFindings(context.Context, *ExportFindingsRequest) (*ExportFindingsResponse, error)
	// SaveMissionDraft persists a mission YAML draft for later use.
	// If draft_id is empty a new draft is created; otherwise the existing draft
	// is updated. Drafts expire automatically after 30 days.
	SaveMissionDraft(context.Context, *SaveMissionDraftRequest) (*SaveMissionDraftResponse, error)
	// ListMissionDrafts returns all saved mission drafts for a tenant, ordered
	// by update time descending.
	ListMissionDrafts(context.Context, *ListMissionDraftsRequest) (*ListMissionDraftsResponse, error)
	// GetTenantQuota retrieves the configured resource quotas for a tenant.
	// Returns zero values for any quota not explicitly set.
	// Requires FGA admin relation on the tenant.
	GetTenantQuota(context.Context, *GetTenantQuotaRequest) (*GetTenantQuotaResponse, error)
	// SetTenantQuota sets or updates the resource quotas for a tenant.
	// Requires platform-operator role.
	SetTenantQuota(context.Context, *SetTenantQuotaRequest) (*SetTenantQuotaResponse, error)
	// GetUserSessions returns the active Keycloak sessions for a user.
	// Accessible by the user themselves or by a tenant admin.
	GetUserSessions(context.Context, *GetUserSessionsRequest) (*GetUserSessionsResponse, error)
	// ListAlerts returns platform alerts for a tenant user.
	// Supports filtering to unread-only alerts.
	ListAlerts(context.Context, *ListAlertsRequest) (*ListAlertsResponse, error)
	// MarkAlertRead marks a single alert as read.
	MarkAlertRead(context.Context, *MarkAlertReadRequest) (*MarkAlertReadResponse, error)
	// MarkAllAlertsRead marks all alerts for a user as read.
	MarkAllAlertsRead(context.Context, *MarkAllAlertsReadRequest) (*MarkAllAlertsReadResponse, error)
	// ListConversations returns the conversation history list for a user.
	ListConversations(context.Context, *ListConversationsRequest) (*ListConversationsResponse, error)
	// GetConversation returns the full message history for a single conversation.
	GetConversation(context.Context, *GetConversationRequest) (*GetConversationResponse, error)
	mustEmbedUnimplementedDaemonAdminServiceServer()
}

